import { isValid } from 'date-fns';
import { format, utcToZonedTime } from 'date-fns-tz';

import type { DateValue, Nullable } from './Calendar.types';
import { DAYS_IN_WEEK, ISO_FORMAT_PATTERN, ONE_DAY, SUNDAY_INDEX } from './constants';
import type { Day } from './views/CalendarDayView/CalendarDayView.types';

export const isFilledDate = (
	value: DateValue,
	options: {
		pattern?: RegExp;
		isPartial?: boolean;
	} = {},
): boolean => {
	const { pattern = ISO_FORMAT_PATTERN, isPartial = false } = options;

	if (isRangeMode(value)) {
		return isPartial ? value.some(date => date && pattern.test(date)) : value.every(date => date && pattern.test(date));
	}

	return pattern.test(value);
};

export const formatToISO = (date: Date, outputDateFormat: string): string => {
	const formatInTimeZone = (date: Date, fmt: string, tz: string): string =>
		format(utcToZonedTime(date, tz), fmt, { timeZone: tz });
	return formatInTimeZone(date, outputDateFormat, 'UTC');
};

